int repeatedStringMatch(char A[], char B[]) {
    int lenA = strlen(A);
    int lenB = strlen(B);
    char repeated[30050];  // Enough to handle (lenA * 3) safely since max |A|,|B| = 10^4
    strcpy(repeated, A);
    int count = 1;

    // Keep appending until repeated string length >= lenB
    while ((int)strlen(repeated) < lenB) {
        strcat(repeated, A);
        count++;
    }

    // Check if B is a substring of the current repeated string
    if (strstr(repeated, B) != NULL)
        return count;

    // Append once more and check again (handles overlap)
    strcat(repeated, A);
    count++;
    if (strstr(repeated, B) != NULL)
        return count;

    // Not possible
    return -1;
}

