public static int repeatedStringMatch(String A, String B) {
    StringBuilder sb = new StringBuilder(A);
    int count = 1;

    // Repeat A until it is at least as long as B
    while (sb.length() < B.length()) {
        sb.append(A);
        count++;
    }

    // First check
    if (sb.indexOf(B) != -1) {
        return count;
    }

    // Second check (append one more time)
    sb.append(A);
    count++;

    if (sb.indexOf(B) != -1) {
        return count;
    }

    return -1;
}

