    let repeatedA = A;
    let count = 1;

    // Repeat A until length is sufficient
    while (repeatedA.length < B.length) {
        repeatedA += A;
        count++;
    }

    // First check
    if (repeatedA.includes(B)) {
        return count;
    }

    // Second check (append one more time)
